7	// Interface for Anthropic model entries
8	interface AnthropicModel {
9	    id: string;
10	    name: string;
11	    type: string;
12	}
13	
14	/**
15	 * @swagger
16	 * /api/anthropic/models:
17	 *   post:
18	 *     summary: List available models from Anthropic
19	 *     operationId: anthropic-list-models
20	 *     requestBody:
21	 *       required: false
22	 *       content:
23	 *         application/json:
24	 *           schema:
25	 *             type: object
26	 *             properties:
27	 *               baseUrl:
28	 *                 type: string
29	 *                 description: Optional custom Anthropic API base URL
30	 *     responses:
31	 *       '200':
32	 *         description: List of available Anthropic models
33	 *         content:
34	 *           application/json:
35	 *             schema:
36	 *               type: object
37	 *               properties:
38	 *                 success:
39	 *                   type: boolean
40	 *                 chatModels:
41	 *                   type: array
42	 *                   items:
43	 *                     type: object
44	 *                     properties:
45	 *                       id:
46	 *                         type: string
47	 *                       name:
48	 *                         type: string
49	 *                       type:
50	 *                         type: string
51	 *       '500':
52	 *         description: Error listing models
53	 *     security:
54	 *       - session: []
55	 *     tags: ["llm"]
56	 */
57	async function listModels(req: Request, res: Response) {
58	    try {
59	        const { baseUrl } = req.body;
60	
61	        // Use provided base URL or default from options
62	        const anthropicBaseUrl = baseUrl ||
63	            await options.getOption('anthropicBaseUrl') ||
64	            PROVIDER_CONSTANTS.ANTHROPIC.BASE_URL;
65	
66	        const apiKey = await options.getOption('anthropicApiKey');
67	
68	        if (!apiKey) {
69	            throw new Error('Anthropic API key is not configured');
70	        }
71	
72	        log.info(`Using predefined Anthropic models list (avoiding direct API call)`);
73	
74	        // Instead of using the SDK's built-in models listing which might not work,
75	        // directly use the predefined available models
76	        const chatModels = PROVIDER_CONSTANTS.ANTHROPIC.AVAILABLE_MODELS.map(model => ({
77	            id: model.id,
78	            name: model.name,
79	            type: 'chat'
80	        }));
81	
82	        // Return the models list
83	        return {
84	            success: true,
85	            chatModels
86	        };
87	    } catch (error: any) {
88	        log.error(`Error listing Anthropic models: ${error.message || 'Unknown error'}`);
89	
90	        // Properly throw the error to be handled by the global error handler
91	        throw new Error(`Failed to list Anthropic models: ${error.message || 'Unknown error'}`);
92	    }
93	}
94	
95	export default {
96	    listModels
97	};
