22	    // We need to get the last focused window from allWindows. If the last window is closed, we return the previous window.
23	    // Therefore, we need to push the window into the allWindows array every time it gets focused.
24	    win.on("focus", () => {
25	        allWindows = allWindows.filter(w => !w.isDestroyed() && w !== win);
26	        allWindows.push(win);
