43	function getSharedSubTreeRoot(note: SNote | BNote | undefined): Subroot {
44	    if (!note || note.noteId === shareRoot.SHARE_ROOT_NOTE_ID) {
45	        // share root itself is not shared
46	        return {};
47	    }
48	
49	    // every path leads to share root, but which one to choose?
50	    // for the sake of simplicity, URLs are not note paths
51	    const parentBranch = note.getParentBranches()[0];
52	
53	    if (note instanceof BNote) {
54	        return {
55	            note,
56	            branch: parentBranch
57	        }
58	    }
59	
60	    if (parentBranch.parentNoteId === shareRoot.SHARE_ROOT_NOTE_ID) {
61	        return {
62	            note,
63	            branch: parentBranch
64	        };
65	    }
66	
67	    return getSharedSubTreeRoot(parentBranch.getParentNote());
68	}
