93	export function renderNoteContent(note: SNote) {
94	    const subRoot = getSharedSubTreeRoot(note);
95	
96	    const ancestors: string[] = [];
97	    let notePointer = note;
98	    while (notePointer.parents[0]?.noteId !== subRoot.note?.noteId) {
99	        const pointerParent = notePointer.parents[0];
100	        if (!pointerParent) {
101	            break;
102	        }
103	        ancestors.push(pointerParent.noteId);
104	        notePointer = pointerParent;
105	    }
106	
107	    // Determine CSS to load.
108	    const cssToLoad: string[] = [];
109	    if (!note.isLabelTruthy("shareOmitDefaultCss")) {
110	        cssToLoad.push(`assets/styles.css`);
111	        cssToLoad.push(`assets/scripts.css`);
112	    }
113	    for (const cssRelation of note.getRelations("shareCss")) {
114	        cssToLoad.push(`api/notes/${cssRelation.value}/download`);
115	    }
116	
117	    // Determine JS to load.
118	    const jsToLoad: string[] = [
119	        "assets/scripts.js"
120	    ];
121	    for (const jsRelation of note.getRelations("shareJs")) {
122	        jsToLoad.push(`api/notes/${jsRelation.value}/download`);
123	    }
124	
125	    const customLogoId = note.getRelation("shareLogo")?.value;
126	    const logoUrl = customLogoId ? `api/images/${customLogoId}/image.png` : `../${assetUrlFragment}/images/icon-color.svg`;
127	
128	    return renderNoteContentInternal(note, {
129	        subRoot,
130	        rootNoteId: "_share",
131	        cssToLoad,
132	        jsToLoad,
133	        logoUrl,
134	        ancestors,
135	        isStatic: false,
136	        faviconUrl: note.hasRelation("shareFavicon") ? `api/notes/${note.getRelationValue("shareFavicon")}/download` : `../favicon.ico`
137	    });
