151	function renderNoteContentInternal(note: SNote | BNote, renderArgs: RenderArgs) {
152	    const { header, content, isEmpty } = getContent(note);
153	    const showLoginInShareTheme = options.getOption("showLoginInShareTheme");
154	    const opts = {
155	        note,
156	        header,
157	        content,
158	        isEmpty,
159	        assetPath: shareAdjustedAssetPath,
160	        assetUrlFragment,
161	        showLoginInShareTheme,
162	        t,
163	        isDev,
164	        utils,
165	        ...renderArgs,
166	    };
167	
168	    // Check if the user has their own template.
169	    if (note.hasRelation("shareTemplate")) {
170	        // Get the template note and content
171	        const templateId = note.getRelation("shareTemplate")?.value;
172	        const templateNote = templateId && shaca.getNote(templateId);
173	
174	        // Make sure the note type is correct
175	        if (templateNote && templateNote.type === "code" && templateNote.mime === "application/x-ejs") {
176	            // EJS caches the result of this so we don't need to pre-cache
177	            const includer = (path: string) => {
178	                const childNote = templateNote.children.find((n) => path === n.title);
179	                if (!childNote) throw new Error(`Unable to find child note: ${path}.`);
180	                if (childNote.type !== "code" || childNote.mime !== "application/x-ejs") throw new Error("Incorrect child note type.");
181	
182	                const template = childNote.getContent();
183	                if (typeof template !== "string") throw new Error("Invalid template content type.");
184	
185	                return { template };
186	            };
187	
188	            // Try to render user's template, w/ fallback to default view
189	            try {
190	                const content = templateNote.getContent();
191	                if (typeof content === "string") {
192	                    return ejs.render(content, opts, { includer });
193	                }
194	            } catch (e: unknown) {
195	                const [errMessage, errStack] = safeExtractMessageAndStackFromError(e);
196	                log.error(`Rendering user provided share template (${templateId}) threw exception ${errMessage} with stacktrace: ${errStack}`);
197	            }
198	        }
199	    }
200	
201	    // Render with the default view otherwise.
202	    const templatePath = getDefaultTemplatePath("page");
203	    return ejs.render(readTemplate(templatePath), opts, {
204	        includer: (path) => {
205	            // Path is relative to apps/server/dist/assets/views
206	            return { template: readTemplate(getDefaultTemplatePath(path)) };
207	        }
208	    });
209	}
