211	export function getDefaultTemplatePath(template: string) {
212	    // Path is relative to apps/server/dist/assets/views
213	    return process.env.NODE_ENV === "development"
214	        ? join(__dirname, `../../../../packages/share-theme/src/templates/${template}.ejs`)
215	        : join(getResourceDir(), `share-theme/templates/${template}.ejs`);
