218	export function readTemplate(path: string) {
219	    const cachedTemplate = templateCache.get(path);
220	    if (cachedTemplate) {
221	        return cachedTemplate;
222	    }
223	
224	    const templateString = readFileSync(path, "utf-8");
225	    templateCache.set(path, templateString);
226	    return templateString;
227	}
