229	export function getContent(note: SNote | BNote) {
230	    if (note.isProtected) {
231	        return {
232	            header: "",
233	            content: "<p>Protected note cannot be displayed</p>",
234	            isEmpty: false
235	        };
236	    }
237	
238	    const result: Result = {
239	        content: note.getContent(),
240	        header: "",
241	        isEmpty: false
242	    };
243	
244	    if (note.type === "text") {
245	        renderText(result, note);
246	    } else if (note.type === "code") {
247	        renderCode(result);
248	    } else if (note.type === "mermaid") {
249	        renderMermaid(result, note);
250	    } else if (["image", "canvas", "mindMap"].includes(note.type)) {
251	        renderImage(result, note);
252	    } else if (note.type === "file") {
253	        renderFile(note, result);
254	    } else if (note.type === "book") {
255	        result.isEmpty = true;
256	    } else if (note.type === "webView") {
257	        renderWebView(note, result);
258	    } else {
259	        result.content = `<p>${t("content_renderer.note-cannot-be-displayed")}</p>`;
260	    }
261	
262	    return result;
263	}
