265	function renderIndex(result: Result) {
266	    result.content += '<ul id="index">';
267	
268	    const rootNote = shaca.getNote(shareRoot.SHARE_ROOT_NOTE_ID);
269	
270	    for (const childNote of rootNote.getChildNotes()) {
271	        const isExternalLink = childNote.hasLabel("shareExternalLink");
272	        const href = isExternalLink ? childNote.getLabelValue("shareExternalLink") : `./${childNote.shareId}`;
273	        const target = isExternalLink ? `target="_blank" rel="noopener noreferrer"` : "";
274	        result.content += `<li><a class="${childNote.type}" href="${href}" ${target}>${childNote.escapedTitle}</a></li>`;
275	    }
276	
277	    result.content += "</ul>";
278	}
