280	function renderText(result: Result, note: SNote | BNote) {
281	    if (typeof result.content !== "string") return;
282	    const parseOpts: Partial<Options> = {
283	        blockTextElements: {}
284	    }
285	    const document = parse(result.content || "", parseOpts);
286	
287	    // Process include notes.
288	    for (const includeNoteEl of document.querySelectorAll("section.include-note")) {
289	        const noteId = includeNoteEl.getAttribute("data-note-id");
290	        if (!noteId) continue;
291	
292	        const note = shaca.getNote(noteId);
293	        if (!note) continue;
294	
295	        const includedResult = getContent(note);
296	        if (typeof includedResult.content !== "string") continue;
297	
298	        const includedDocument = parse(includedResult.content, parseOpts).childNodes;
299	        if (includedDocument) {
300	            includeNoteEl.replaceWith(...includedDocument);
301	        }
302	    }
303	
304	    result.isEmpty = document.textContent?.trim().length === 0 && document.querySelectorAll("img").length === 0;
305	
306	    const getNote: GetNoteFunction = note instanceof BNote
307	        ? (noteId: string) => becca.getNote(noteId)
308	        : (noteId: string) => shaca.getNote(noteId);
309	    const getAttachment = note instanceof BNote
310	        ? (attachmentId: string) => becca.getAttachment(attachmentId)
311	        : (attachmentId: string) => shaca.getAttachment(attachmentId);
312	
313	    if (!result.isEmpty) {
314	        // Process attachment links.
315	        for (const linkEl of document.querySelectorAll("a")) {
316	            const href = linkEl.getAttribute("href");
317	
318	            // Preserve footnotes.
319	            if (href?.startsWith("#fn")) {
320	                continue;
321	            }
322	
323	            if (href?.startsWith("#")) {
324	                handleAttachmentLink(linkEl, href, getNote, getAttachment);
325	            }
326	
327	            if (linkEl.classList.contains("reference-link")) {
328	                cleanUpReferenceLinks(linkEl, getNote);
329	            }
330	        }
331	
332	        // Apply syntax highlight.
333	        for (const codeEl of document.querySelectorAll("pre code")) {
334	            if (codeEl.classList.contains("language-mermaid") && note.type === "text") {
335	                // Mermaid is handled on client-side, we don't want to break it by adding syntax highlighting.
336	                continue;
337	            }
338	
339	            const highlightResult = highlightAuto(codeEl.text);
340	            codeEl.innerHTML = highlightResult.value;
341	            codeEl.classList.add("hljs");
342	        }
343	
344	        result.content = document.innerHTML ?? "";
345	
346	        if (note.hasLabel("shareIndex")) {
347	            renderIndex(result);
348	        }
349	    }
350	}
351	
352	function handleAttachmentLink(linkEl: HTMLElement, href: string, getNote: GetNoteFunction, getAttachment: (id: string) => BAttachment | SAttachment | null) {
353	    const linkRegExp = /attachmentId=([a-zA-Z0-9_]+)/g;
354	    let attachmentMatch;
355	    if ((attachmentMatch = linkRegExp.exec(href))) {
356	        const attachmentId = attachmentMatch[1];
357	        const attachment = getAttachment(attachmentId);
358	
359	        if (attachment) {
360	            linkEl.setAttribute("href", `api/attachments/${attachmentId}/download`);
361	            linkEl.classList.add(`attachment-link`);
362	            linkEl.classList.add(`role-${attachment.role}`);
363	            linkEl.childNodes.length = 0;
364	            linkEl.appendChild(new TextNode(attachment.title));
365	        } else {
366	            linkEl.removeAttribute("href");
367	            log.error(`Broken attachment link detected in shared note: unable to find attachment with ID ${attachmentId}`);
368	        }
369	    } else {
370	        const [notePath] = href.split("?");
371	        const notePathSegments = notePath.split("/");
372	        const noteId = notePathSegments[notePathSegments.length - 1];
373	        const linkedNote = getNote(noteId);
374	        if (linkedNote) {
375	            const isExternalLink = linkedNote.hasLabel("shareExternalLink");
376	            const href = isExternalLink ? linkedNote.getLabelValue("shareExternalLink") : `./${linkedNote.shareId}`;
377	            if (href) {
378	                linkEl.setAttribute("href", href);
379	            }
380	            if (isExternalLink) {
381	                linkEl.setAttribute("target", "_blank");
382	                linkEl.setAttribute("rel", "noopener noreferrer");
383	            }
384	            linkEl.classList.add(`type-${linkedNote.type}`);
385	        } else {
386	            log.error(`Broken link detected in shared note: unable to find note with ID ${noteId}`);
387	            linkEl.removeAttribute("href");
388	        }
389	    }
390	}
