392	/**
393	 * Processes reference links to ensure that they are up to date. More specifically, reference links contain in their HTML source code the note title at the time of the linking. It can be changed in the mean-time or the note can become protected, which leaks information.
394	 *
395	 * @param linkEl the <a> element to process.
396	 */
397	function cleanUpReferenceLinks(linkEl: HTMLElement, getNote: GetNoteFunction) {
398	    // Note: this method is basically a reimplementation of getReferenceLinkTitleSync from the link service of the client.
399	    const href = linkEl.getAttribute("href") ?? "";
400	    if (linkEl.classList.contains("attachment-link")) return;

400	    if (linkEl.classList.contains("attachment-link")) return;
401	
402	    const noteId = href.split("/").at(-1);
403	    const note = noteId ? getNote(noteId) : undefined;
404	    if (!note) {
405	        // If a note is not found, simply replace it with a text.
406	        linkEl.replaceWith(new TextNode(linkEl.innerText));
407	    } else if (note.isProtected) {
408	        linkEl.innerHTML = "[protected]";
409	    } else {
410	        linkEl.innerHTML = `<span><span class="${note.getIcon()}"></span>${utils.escapeHtml(note.title)}</span>`;
411	    }
412	}
