414	/**
415	 * Renders a code note.
416	 */
417	export function renderCode(result: Result) {
418	    if (typeof result.content !== "string" || !result.content?.trim()) {
419	        result.isEmpty = true;
420	    } else {
421	        const preEl = new HTMLElement("pre", {});
422	        preEl.appendChild(new TextNode(result.content));
423	        result.content = preEl.outerHTML;
424	    }
425	}
