427	function renderMermaid(result: Result, note: SNote | BNote) {
428	    if (typeof result.content !== "string") {
429	        return;
430	    }
431	
432	    result.content = `
433	<img src="api/images/${note.noteId}/${note.encodedTitle}?${note.utcDateModified}">
434	<hr>
435	<details>
436	    <summary>Chart source</summary>
437	    <pre>${escapeHtml(result.content)}</pre>
438	</details>`;
439	}
440	
441	function renderImage(result: Result, note: SNote | BNote) {
442	    result.content = `<img src="api/images/${note.noteId}/${note.encodedTitle}?${note.utcDateModified}">`;
443	}
444	
445	function renderFile(note: SNote | BNote, result: Result) {
446	    if (note.mime === "application/pdf") {
447	        result.content = `<iframe class="pdf-view" src="api/notes/${note.noteId}/view"></iframe>`;
448	    } else {
449	        result.content = `<button type="button" onclick="location.href='api/notes/${note.noteId}/download'">Download file</button>`;
450	    }
451	}
452	
453	function renderWebView(note: SNote | BNote, result: Result) {
454	    const url = note.getLabelValue("webViewSrc");
455	    if (!url) return;
456	
457	    result.content = `<iframe class="webview" src="${sanitizeUrl(url)}" sandbox="allow-same-origin allow-scripts allow-popups"></iframe>`;
458	}
