7	/**
8	 * Format markdown content for display
9	 */
10	export function formatMarkdown(content: string): string {
11	    if (!content) return '';
12	
13	    // First, extract HTML thinking visualization to protect it from replacements
14	    const thinkingBlocks: string[] = [];
15	    let processedContent = content.replace(/<div class=['"](thinking-process|reasoning-process)['"][\s\S]*?<\/div>/g, (match) => {
16	        const placeholder = `__THINKING_BLOCK_${thinkingBlocks.length}__`;
17	        thinkingBlocks.push(match);
18	        return placeholder;
19	    });
20	
21	    // Use marked library to parse the markdown
22	    const markedContent = marked(processedContent, {
23	        breaks: true,   // Convert line breaks to <br>
24	        gfm: true,      // Enable GitHub Flavored Markdown
25	        silent: true    // Ignore errors
26	    });
27	
28	    // Handle potential promise (though it shouldn't be with our options)
29	    if (typeof markedContent === 'string') {
30	        processedContent = markedContent;
31	    } else {
32	        console.warn('Marked returned a promise unexpectedly');
33	        // Use the original content as fallback
34	        processedContent = content;
35	    }
36	
37	    // Restore thinking visualization blocks
38	    thinkingBlocks.forEach((block, index) => {
39	        processedContent = processedContent.replace(`__THINKING_BLOCK_${index}__`, block);
40	    });
41	
42	    return processedContent;
43	}
44	
45	/**
46	 * Simple HTML escaping for safer content display
47	 */
48	export function escapeHtml(text: string): string {
49	    if (typeof text !== 'string') {
50	        text = String(text || '');
51	    }
52	
53	    return text
54	        .replace(/&/g, '&amp;')
55	        .replace(/</g, '&lt;')
56	        .replace(/>/g, '&gt;')
57	        .replace(/"/g, '&quot;')
58	        .replace(/'/g, '&#039;');
59	}
60	
61	/**
62	 * Apply syntax highlighting to content
63	 */
64	export function applyHighlighting(element: HTMLElement): void {
65	    formatCodeBlocks($(element));
66	}
67	
68	/**
69	 * Format tool arguments for display
70	 */
71	export function formatToolArgs(args: any): string {
72	    if (!args || typeof args !== 'object') return '';
73	
74	    return Object.entries(args)
75	        .map(([key, value]) => {
76	            // Format the value based on its type
77	            let displayValue;
78	            if (typeof value === 'string') {
79	                displayValue = value.length > 50 ? `"${value.substring(0, 47)}..."` : `"${value}"`;
80	            } else if (value === null) {
81	                displayValue = 'null';
82	            } else if (Array.isArray(value)) {
83	                displayValue = '[...]'; // Simplified array representation
84	            } else if (typeof value === 'object') {
85	                displayValue = '{...}'; // Simplified object representation
86	            } else {
87	                displayValue = String(value);
88	            }
89	
90	            return `<span class="text-primary">${escapeHtml(key)}</span>: ${escapeHtml(displayValue)}`;
91	        })
92	        .join(', ');
93	}
