32	export default function DeleteNotesDialog() {
33	    const [ opts, setOpts ] = useState<ShowDeleteNotesDialogOpts>({});
34	    const [ deleteAllClones, setDeleteAllClones ] = useState(false);
35	    const [ eraseNotes, setEraseNotes ] = useState(!!opts.forceDeleteAllClones);
36	    const [ brokenRelations, setBrokenRelations ] = useState<DeleteNotesPreview["brokenRelations"]>([]);
37	    const [ noteIdsToBeDeleted, setNoteIdsToBeDeleted ] = useState<DeleteNotesPreview["noteIdsToBeDeleted"]>([]);    
38	    const [ shown, setShown ] = useState(false);
39	    const okButtonRef = useRef<HTMLButtonElement>(null);
40	
41	    useTriliumEvent("showDeleteNotesDialog", (opts) => {
42	        setOpts(opts);
43	        setShown(true);
44	    })
45	
46	    useEffect(() => {
47	        const { branchIdsToDelete, forceDeleteAllClones } = opts;
48	        if (!branchIdsToDelete || branchIdsToDelete.length === 0) {
49	            return;
50	        }        
51	
52	        server.post<DeleteNotesPreview>("delete-notes-preview", {
53	            branchIdsToDelete,
54	            deleteAllClones: forceDeleteAllClones || deleteAllClones
55	        }).then(response => {
56	            setBrokenRelations(response.brokenRelations);
57	            setNoteIdsToBeDeleted(response.noteIdsToBeDeleted);
58	        });
59	    }, [ opts, deleteAllClones ]);
60	
61	    return (
62	        <Modal
63	            className="delete-notes-dialog"
64	            size="xl"
65	            scrollable
66	            title={t("delete_notes.delete_notes_preview")}
67	            onShown={() => okButtonRef.current?.focus()}
68	            onHidden={() => {
69	                opts.callback?.({ proceed: false })
70	                setShown(false);
71	            }}
72	            footer={<>
73	                <Button text={t("delete_notes.cancel")}
74	                    onClick={() => setShown(false)} />
75	                <Button text={t("delete_notes.ok")} primary
76	                    buttonRef={okButtonRef}
77	                    onClick={() => {
78	                        opts.callback?.({ proceed: true, deleteAllClones, eraseNotes });
79	                        setShown(false);
80	                    }} />
81	            </>}
82	            show={shown}
83	        >
84	            <FormCheckbox name="delete-all-clones" label={t("delete_notes.delete_all_clones_description")}
85	                currentValue={deleteAllClones} onChange={setDeleteAllClones}
86	            />
87	            <FormCheckbox
88	                name="erase-notes" label={t("delete_notes.erase_notes_warning")}
89	                disabled={opts.forceDeleteAllClones}
90	                currentValue={eraseNotes} onChange={setEraseNotes}
91	            />
92	
93	            <DeletedNotes noteIdsToBeDeleted={noteIdsToBeDeleted} />
94	            <BrokenRelations brokenRelations={brokenRelations} />
95	        </Modal>
96	    );
97	}
