99	function DeletedNotes({ noteIdsToBeDeleted }: { noteIdsToBeDeleted: DeleteNotesPreview["noteIdsToBeDeleted"] }) {
100	    const [ noteLinks, setNoteLinks ] = useState<string[]>([]);
101	
102	    useEffect(() => {
103	        froca.getNotes(noteIdsToBeDeleted).then(async (notes: FNote[]) => {
104	            const noteLinks: string[] = [];
105	
106	            for (const note of notes) {
107	                noteLinks.push((await link.createLink(note.noteId, { showNotePath: true })).html());
108	            }
109	
110	            setNoteLinks(noteLinks);
111	        });
112	    }, [noteIdsToBeDeleted]);
113	
114	    if (noteIdsToBeDeleted.length) {
115	        return (
116	            <div className="delete-notes-list-wrapper" style={{paddingTop: "16px"}}>
117	                <h4>{t("delete_notes.notes_to_be_deleted", { notesCount: noteIdsToBeDeleted.length })}</h4>
118	    
119	                <ul className="delete-notes-list" style={{ maxHeight: "200px", overflow: "auto"}}>
120	                    {noteLinks.map((link, index) => (
121	                        <li key={index} dangerouslySetInnerHTML={{ __html: link }} />
122	                    ))}
123	                </ul>
124	            </div>
125	        );
126	    } else {
127	        return (
128	            <Alert type="info">
129	                {t("delete_notes.no_note_to_delete")}
130	            </Alert>
131	        )
132	    }
133	}
134	
135	function BrokenRelations({ brokenRelations }: { brokenRelations: DeleteNotesPreview["brokenRelations"] }) {
136	    const [ notesWithBrokenRelations, setNotesWithBrokenRelations ] = useState<BrokenRelationData[]>([]);
137	
138	    useEffect(() => {
139	        const noteIds = brokenRelations
140	            .map(relation => relation.noteId)
141	            .filter(noteId => noteId) as string[];
142	        froca.getNotes(noteIds).then(async () => {
143	            const notesWithBrokenRelations: BrokenRelationData[] = [];
144	            for (const attr of brokenRelations) {
145	                notesWithBrokenRelations.push({
146	                    note: (await link.createLink(attr.value)).html(),
147	                    relation: `<code>${attr.name}</code>`,
148	                    source: (await link.createLink(attr.noteId)).html()
149	                });
150	            }
151	            setNotesWithBrokenRelations(notesWithBrokenRelations);
152	        });
153	    }, [brokenRelations]);
154	
155	    if (brokenRelations.length) {
156	        return (
157	            <Alert type="danger" title={t("delete_notes.broken_relations_to_be_deleted", { relationCount: brokenRelations.length })}>
158	                <ul className="broken-relations-list" style={{ maxHeight: "200px", overflow: "auto" }}>
159	                    {brokenRelations.map((_, index) => {
160	                        return (
161	                            <li key={index}>
162	                                <span dangerouslySetInnerHTML={{ __html: t("delete_notes.deleted_relation_text", notesWithBrokenRelations[index] as unknown as Record<string, string>) }} />
163	                            </li>
164	                        );
165	                    })}
166	                </ul>
167	            </Alert>
168	        );
169	    } else {
170	        return <></>;
171	    }
172	}
