8	interface ConfirmDialogProps {
9	    title?: string;
10	    message?: string | HTMLElement;
11	    callback?: ConfirmDialogCallback;
12	    isConfirmDeleteNoteBox?: boolean;   
13	}
14	
15	export default function ConfirmDialog() {
16	    const [ opts, setOpts ] = useState<ConfirmDialogProps>();
17	    const [ isDeleteNoteChecked, setIsDeleteNoteChecked ] = useState(false);
18	    const [ shown, setShown ] = useState(false);
19	
20	    function showDialog(title: string | null, message: MessageType, callback: ConfirmDialogCallback, isConfirmDeleteNoteBox: boolean) {
21	        setOpts({
22	            title: title ?? undefined,
23	            message: (typeof message === "object" && "length" in message ? message[0] : message),
24	            callback,
25	            isConfirmDeleteNoteBox
26	        });
27	        setShown(true);
28	    }
29	
30	    useTriliumEvent("showConfirmDialog", ({ message, callback }) => showDialog(null, message, callback, false));
31	    useTriliumEvent("showConfirmDeleteNoteBoxWithNoteDialog", ({ title, callback }) => showDialog(title, t("confirm.are_you_sure_remove_note", { title: title }), callback, true));
32	
33	    return ( 
34	        <Modal
35	            className="confirm-dialog"
36	            title={opts?.title ?? t("confirm.confirmation")}
37	            size="md"
38	            zIndex={2000}
39	            scrollable={true}
40	            onHidden={() => {
41	                opts?.callback?.({
42	                    confirmed: false,
43	                    isDeleteNoteChecked
44	                });
45	                setShown(false);
46	            }}
47	            footer={<>
48	                <Button text={t("confirm.cancel")} onClick={() => setShown(false)} />
49	                <Button text={t("confirm.ok")} onClick={() => {
50	                    opts?.callback?.({
51	                        confirmed: true,
52	                        isDeleteNoteChecked
53	                    });
54	                    setShown(false);
55	                }} />
56	            </>}
57	            show={shown}
58	            stackable
59	        >
60	            {!opts?.message || typeof opts?.message === "string"
61	                ? <div>{(opts?.message as string) ?? ""}</div>
62	                : <div dangerouslySetInnerHTML={{ __html: opts?.message.outerHTML ?? "" }} />}
63	
64	            {opts?.isConfirmDeleteNoteBox && (
65	                <FormCheckbox
66	                    name="confirm-dialog-delete-note"
67	                    label={t("confirm.also_delete_note")}
68	                    hint={t("confirm.if_you_dont_check")}
69	                    currentValue={isDeleteNoteChecked} onChange={setIsDeleteNoteChecked} />
70	            )}
71	        </Modal>
72	    );
73	}
74	
75	export type ConfirmDialogResult = false | ConfirmDialogOptions;
76	export type ConfirmDialogCallback = (val?: ConfirmDialogResult) => void;
77	type MessageType = string | HTMLElement | JQuery<HTMLElement>;
78	
79	export interface ConfirmDialogOptions {
80	    confirmed: boolean;
81	    isDeleteNoteChecked: boolean;
82	}
83	
84	export interface ConfirmWithMessageOptions {
85	    message: MessageType;
86	    callback: ConfirmDialogCallback;
87	}
