1	import type { CSSProperties, HTMLProps, RefObject } from "preact/compat";
2	
3	type HTMLElementLike = string | HTMLElement | JQuery<HTMLElement>;
4	
5	interface RawHtmlProps extends Pick<HTMLProps<HTMLElement>, "tabindex" | "dir"> {
6	    className?: string;
7	    html?: HTMLElementLike;
8	    style?: CSSProperties;
9	    onClick?: (e: MouseEvent) => void;
10	}
11	
12	export default function RawHtml({containerRef, ...props}: RawHtmlProps & { containerRef?: RefObject<HTMLSpanElement>}) {
13	    return <span ref={containerRef} {...getProps(props)} />;
14	}
15	
16	export function RawHtmlBlock({containerRef, ...props}: RawHtmlProps & { containerRef?: RefObject<HTMLDivElement>}) {
17	    return <div ref={containerRef} {...getProps(props)} />
18	}
19	
20	function getProps({ className, html, style, onClick }: RawHtmlProps) {
21	    return {
22	        className: className,
23	        dangerouslySetInnerHTML: getHtml(html ?? ""),
24	        style,
25	        onClick
26	    }
27	}
28	
29	export function getHtml(html: string | HTMLElement | JQuery<HTMLElement>) {
30	    if (typeof html === "object" && "length" in html) {
31	        html = html[0];
32	    }
33	
34	    if (typeof html === "object" && "outerHTML" in html) {
35	        html = html.outerHTML;
36	    }
37	
38	    return {
39	        __html: html as string
40	    };
41	}
